/**
 * PressVideo — Lazy iframe injector + YouTube IFrame API.
 * Vanilla JS. No jQuery.
 */
(function(){'use strict';const CANVAS_ID='pv-canvas';const AUTOPLAY_MS=2500;let canvas,holder,spinner;let spinnerTimer=null;let ytPlayer=null;let ytApiReady=!!(window.YT&&window.YT.Player);let ytApiQueue=[];(function loadYtApi(){if(ytApiReady||document.getElementById('pv-yt-api'))return;var prev=window.onYouTubeIframeAPIReady;window.onYouTubeIframeAPIReady=function(){if(typeof prev==='function')prev();ytApiReady=true;ytApiQueue.forEach(function(fn){fn()});ytApiQueue=[]};var s=document.createElement('script');s.id='pv-yt-api';s.src='https://www.youtube.com/iframe_api';document.head.appendChild(s)}());function whenYtReady(fn){ytApiReady?fn():ytApiQueue.push(fn)}function init(){canvas=document.getElementById(CANVAS_ID);if(!canvas)return;holder=canvas.querySelector('.pv-iframe-holder');spinner=canvas.querySelector('.pv-spinner');canvas.addEventListener('pv:opened',onOpen);canvas.addEventListener('pv:closed',onClose)}function onOpen(){if(!holder)return;const embedUrl=holder.dataset.embedUrl;if(!embedUrl||holder.dataset.loaded)return;showSpinner();const url=new URL(embedUrl.replace('watch?v=','embed/'));url.searchParams.set('autoplay','1');url.searchParams.set('rel','0');url.searchParams.set('modestbranding','1');url.searchParams.set('playsinline','1');url.searchParams.set('enablejsapi','1');const iframe=document.createElement('iframe');iframe.id='pv-yt-iframe';iframe.src=url.toString();iframe.allow='autoplay; fullscreen; picture-in-picture';iframe.allowFullscreen=true;iframe.title=canvas.querySelector('.pv-title')?.textContent||'Video';iframe.addEventListener('load',function(){hideSpinner();holder.dataset.loaded='1'});spinnerTimer=setTimeout(function(){hideSpinner();holder.dataset.loaded='1'},AUTOPLAY_MS);if(ytPlayer){try{ytPlayer.destroy()}catch(e){}ytPlayer=null}holder.innerHTML='';holder.appendChild(iframe);whenYtReady(function(){var el=document.getElementById('pv-yt-iframe');if(!el||!el.isConnected)return;try{ytPlayer=new YT.Player('pv-yt-iframe',{events:{onStateChange:function(e){if(e.data===YT.PlayerState.ENDED){canvas.dispatchEvent(new CustomEvent('pv:video-ended',{bubbles:false}))}}}})}catch(err){}});const ytId=url.pathname.split('/').pop()||'';canvas.dispatchEvent(new CustomEvent('pv:iframe-ready',{bubbles:false,detail:{iframe:iframe,youtubeId:ytId}}))}function onClose(){if(!holder)return;clearTimeout(spinnerTimer);if(ytPlayer){try{ytPlayer.destroy()}catch(e){}ytPlayer=null}holder.innerHTML='';delete holder.dataset.loaded;hideSpinner()}function showSpinner(){if(spinner){spinner.removeAttribute('hidden');spinner.style.display=''}}function hideSpinner(){if(spinner){spinner.style.display='none'}}if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',init)}else{init()}}());
